 }

+// Top-level route segments reserved by the app — series slugs must not collide with these.
+const RESERVED_ROUTE_SEGMENTS = new Set([
+  'series', 'books', 'flows', 'tags', 'authors', 'archive', 'notes', 'graph', 'page', 'api',
+]);
